SELECT * FROM (SELECT TRY_CAST("YEAR" AS INTEGER) AS year, TRY_CAST("MONTH_NUM" AS INTEGER) AS month, TRY_CAST(left(CAST("FLT_DATE" AS VARCHAR), 10) AS DATE) AS date, NULLIF("APT_ICAO", '') AS apt_icao, NULLIF("APT_NAME", '') AS apt_name, NULLIF("STATE_NAME", '') AS state_name, TRY_CAST("FLT_DEP_1" AS DOUBLE) AS flt_dep_1, TRY_CAST("FLT_DEP_REG_1" AS DOUBLE) AS flt_dep_reg_1, TRY_CAST("FLT_DEP_OUT_EARLY_1" AS DOUBLE) AS flt_dep_out_early_1, TRY_CAST("FLT_DEP_IN_1" AS DOUBLE) AS flt_dep_in_1, TRY_CAST("FLT_DEP_OUT_LATE_1" AS DOUBLE) AS flt_dep_out_late_1 FROM "eurocontrol-atfm-slot-adherence") WHERE date IS NOT NULL
